import sys, json
data = json.load(sys.stdin)
positions = []
for row in data:
    c = row['content']
    # Could be JSON string or already parsed — handle both
    if isinstance(c, str) and c.strip():
        try:
            c = json.loads(c)
        except:
            continue
    if isinstance(c, dict):
        positions.append(f\"{c.get('cluster_family','?')} > {c.get('cluster_name','?')} > {c.get('position_name','?')}\")
    else:
        positions.append(f'(non-dict content: {type(c).__name__})')
print(f'Total position_mastery entries: {len(data)}')
for i, p in enumerate(sorted(positions)):
    print(f'  {i+1}. {p}')

# Show any that are empty
for i, row in enumerate(data):
    c = row['content']
    if not c or (isinstance(c, str) and not c.strip()):
        print(f'  WARNING: Entry {i} has empty content')
"
